VALUES
  ('elementary-6f0ba476-moex-00904', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '下列那一個選項不是我國遺產及贈與稅法第16條所稱不計入遺產總額之項目？', '["遺贈人、受遺贈人或繼承人捐贈各級政府及公立教育、文化、公益、慈善機關之財產", "約定於被繼承人死亡時，給付其所指定受益人之人壽保險金額、軍、公教人員、勞工或農民保險之保 險金額", "遺產中作農業使用之農業用地及其地上農作物，由繼承人或受遺贈人承受者", "被繼承人死亡前5年內，繼承之財產已納遺產稅者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "b551c80272d7", "answer_pdf_sha1": "f8c75d40d6c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00905', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依平均地權條例規定，已規定地價之土地，每幾年重新規定地價一次。但必要時得延長之？', '["1年", "2年", "3年", "5年"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "b551c80272d7", "answer_pdf_sha1": "f8c75d40d6c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00906', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依土地稅法規定，下列有關土地增值稅納稅義務人之敘述，何者正確？', '["土地為有償移轉者，為取得所有權之人", "土地為無償移轉者，為原所有權人", "土地設定典權者，為典權人", "受託人就受託土地，於信託關係存續中，有償移轉所有權、設定典權或依信託法第35條第1項規定轉 為其自有土地時，以受託人為納稅義務人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "b551c80272d7", "answer_pdf_sha1": "f8c75d40d6c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00907', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依土地稅法規定，下列有關地價稅納稅義務人之敘述，何者錯誤？', '["設有典權土地，為出典人", "承領土地，為承領人", "承墾土地，為耕作權人", "土地為信託財產者，於信託關係存續中，以受託人為納稅義務人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "b551c80272d7", "answer_pdf_sha1": "f8c75d40d6c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00908', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '加值型及非加值型營業稅法第四章第一節規定計算稅額之營業人，其進項稅額憑證，未於當期申報者， 得延至次期申報扣抵。次期仍未申報者，應於申報扣抵當期敘明理由。但進項稅額憑證之申報扣抵期間， 以幾年為限？', '["1年", "3年", "5年", "10年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "b551c80272d7", "answer_pdf_sha1": "f8c75d40d6c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00909', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '我國土地稅法所稱空地，指已完成道路、排水及電力設施，於有自來水地區並已完成自來水系統，而仍 未依法建築使用；或雖建築使用，而其建築改良物價值不及所占基地申報地價之多少，且經直轄市或縣 （市）政府認定應予增建、改建或重建之私有及公有非公用建築用地？', '["2‰", "10‰", "5%", "10%"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "b551c80272d7", "answer_pdf_sha1": "f8c75d40d6c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00910', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依據我國土地稅法之規定，土地所有權移轉或設定典權，其申報移轉現值之審核標準，下列何者錯誤？', '["申報人逾訂定契約之日起30日始申報者，以受理申報機關收件日當期之公告土地現值為準", "申報人於訂定契約之日起30日內申報者，以訂約日當期之公告土地現值為準", "遺贈之土地，以其受遺贈人申報遺產稅日當期之公告土地現值為準", "依法院判決移轉登記者，以申報人向法院起訴日當期之公告土地現值為準"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "b551c80272d7", "answer_pdf_sha1": "f8c75d40d6c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00911', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '土地所有權人出售其自用住宅用地，適用「一生一屋」土地增值稅優惠稅率之規定，下列何者正確？', '["出售都市土地面積未超過3公畝部分或非都市土地面積未超過7公畝部分", "出售前持有該土地5年以上", "出售前5年內，無供營業使用或出租", "土地所有權人或其配偶、未成年子女於土地出售前，在該地設有戶籍且持有該自用住宅連續滿5年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "b551c80272d7", "answer_pdf_sha1": "f8c75d40d6c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00912', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依土地稅法規定，企業或公營事業興建之勞工宿舍，自動工興建或取得土地所有權之日起，其用地之地 價稅如何徵收？', '["免徵", "按2‰計徵", "按6‰計徵", "按10‰計徵"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "b551c80272d7", "answer_pdf_sha1": "f8c75d40d6c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00913', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依房屋稅條例規定，下列何者正確？', '["房屋為信託財產者，於信託關係存續中，以委託人為房屋稅之納稅義務人", "供自住或公益出租人出租使用者，其稅率為2%", "房屋設有典權者，向出典人徵收之", "房屋同時作住家及非住家用者，應以實際使用面積，分別按住家用或非住家用稅率，課徵房屋稅。但 非住家用者，課稅面積最低不得少於全部面積六分之一"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "b551c80272d7", "answer_pdf_sha1": "f8c75d40d6c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL)
